import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';

export type LiveSessionVm = {
  id: string;
  title: string;
  teacherName: string;
  scheduledAt: string;
  status: 'live' | 'scheduled' | 'ended';
  coverUrl: string;
};

@Component({
  selector: 'app-live-sessions',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './live-sessions.component.html',
  styleUrls: ['./live-sessions.component.scss']
})
export class LiveSessionsComponent {
  isLoading = signal(true);
  activeSession = signal<string | null>(null);

  sessions = signal<LiveSessionVm[]>([
    {
      id: 's1',
      title: 'Correction du devoir de maths',
      teacherName: 'M. Amine',
      scheduledAt: '2026-03-21T14:00:00',
      status: 'live',
      coverUrl: 'https://images.unsplash.com/photo-1509228468518-180dd4864904?auto=format&fit=crop&w=600&q=60'
    },
    {
      id: 's2',
      title: 'Physique — Cinématique',
      teacherName: 'Mme Salma',
      scheduledAt: '2026-03-22T10:00:00',
      status: 'scheduled',
      coverUrl: 'https://images.unsplash.com/photo-1532094349884-543bc11b234d?auto=format&fit=crop&w=600&q=60'
    },
    {
      id: 's3',
      title: 'Anglais — Conversation',
      teacherName: 'Ms. Sarah',
      scheduledAt: '2026-03-23T15:00:00',
      status: 'scheduled',
      coverUrl: 'https://images.unsplash.com/photo-1523240795612-9a054b0db644?auto=format&fit=crop&w=600&q=60'
    }
  ]);

  constructor() {
    setTimeout(() => this.isLoading.set(false), 500);
  }

  joinSession(id: string) {
    this.activeSession.set(id);
  }

  leaveSession() {
    this.activeSession.set(null);
  }

  getStatusClass(status: string): string {
    switch (status) {
      case 'live': return 'bg-red-100 text-red-700';
      case 'scheduled': return 'bg-blue-100 text-blue-700';
      case 'ended': return 'bg-gray-100 text-gray-600';
      default: return 'bg-gray-100 text-gray-600';
    }
  }

  getStatusLabel(status: string): string {
    switch (status) {
      case 'live': return 'En direct';
      case 'scheduled': return 'Planifié';
      case 'ended': return 'Terminé';
      default: return status;
    }
  }
}
<div class="min-h-screen bg-[#F8F9FA] py-8">
  <!-- Jitsi Container -->
  <div *ngIf="activeSession()" class="fixed inset-0 z-50 bg-black">
    <div id="jitsi-container" class="h-full w-full"></div>
    <button (click)="leaveSession()" class="absolute right-4 top-4 z-10 rounded-xl bg-red-600 px-4 py-2 text-sm font-semibold text-white hover:bg-red-700">
      Quitter la session
    </button>
  </div>

  <div class="mx-auto w-full max-w-7xl px-4">
    <!-- Header -->
    <div class="mb-8">
      <h1 class="text-3xl font-bold text-gray-900 sm:text-4xl">Sessions en direct</h1>
      <p class="mt-2 text-gray-600">Rejoignez des cours interactifs en direct avec vos professeurs</p>
    </div>

    <!-- Loading -->
    <div *ngIf="isLoading()" class="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
      <div *ngFor="let x of [1,2,3]" class="overflow-hidden rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
        <div class="h-6 w-1/3 animate-pulse rounded bg-gray-200"></div>
        <div class="mt-4 h-8 animate-pulse rounded bg-gray-200"></div>
        <div class="mt-2 h-4 w-1/2 animate-pulse rounded bg-gray-200"></div>
        <div class="mt-6 h-10 w-full animate-pulse rounded-xl bg-gray-200"></div>
      </div>
    </div>

    <!-- Sessions Grid -->
    <div *ngIf="!isLoading()" class="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
      <div *ngFor="let session of sessions()" class="overflow-hidden rounded-2xl border border-gray-200 bg-white shadow-sm transition hover:shadow-lg">
        <div class="relative aspect-video w-full overflow-hidden bg-gray-100">
          <img [src]="session.coverUrl" [alt]="session.title" class="h-full w-full object-cover" />
          <span [class]="'absolute left-3 top-3 rounded-full px-3 py-1 text-xs font-semibold ' + getStatusClass(session.status)">
            {{ getStatusLabel(session.status) }}
          </span>
        </div>
        <div class="p-5">
          <h3 class="text-lg font-semibold text-gray-900">{{ session.title }}</h3>
          <p class="mt-1 text-sm text-gray-600">{{ session.teacherName }}</p>
          <p class="mt-2 text-sm text-gray-500">{{ session.scheduledAt | date:'dd/MM/yyyy HH:mm' }}</p>
          <button 
            (click)="joinSession(session.id)" 
            [disabled]="session.status !== 'live'"
            class="mt-4 w-full rounded-xl bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] py-2.5 text-sm font-semibold text-white disabled:cursor-not-allowed disabled:opacity-50">
            {{ session.status === 'live' ? 'Rejoindre' : 'Bientôt disponible' }}
          </button>
        </div>
      </div>
    </div>

    <!-- Empty -->
    <div *ngIf="!isLoading() && sessions().length === 0" class="mt-10 rounded-2xl border border-dashed border-gray-300 bg-white p-10 text-center">
      <h3 class="text-lg font-semibold text-gray-900">Aucune session en direct</h3>
      <p class="mt-2 text-sm text-gray-600">Revenez plus tard</p>
    </div>
  </div>
</div>
